SELECT name, established_date
FROM ngos_vos
ORDER BY established_date ASC;

SELECT name, established_date
FROM ngos_vos
WHERE established_date = (
    SELECT MIN(established_date) 
    FROM ngos_vos
);

SELECT name
FROM ngos_vos
WHERE ngo_vo_id IN (
  SELECT ngo_vo_id
  FROM funding
);

SELECT project_id, COUNT(impact_id) AS impact_count
FROM impact
GROUP BY project_id;
